query:
SELECT id, fullName, instagramHandle, team, paymentStatus FROM sports_day_registrations
WHERE fullName LIKE '%Vezza%' OR fullName LIKE '%Vee%' OR instagramHandle LIKE '%vezza%' OR instagramHandle LIKE '%verity%'
ORDER BY fullName;

